const hubspot = require('@hubspot/api-client');
exports.main = (event, callback) => {
    const hubspotClient = new hubspot.Client({"accessToken": process.env.token});

    hubspotClient.crm.associations.v4.basicApi.getPage(
        'deals',
        event.object.objectId,
        'line_items'
    ).then((associationResults) => {
        // get all line item details
        let lineItemPromises = associationResults.results.map(item => {
            return hubspotClient.crm.lineItems.basicApi.getById(
                item.toObjectId, 
                ['name','product_category','manufacturer','quantity','dc_size','ac_size','length','width','size__kwh_']
            ).then(lineItemResults => lineItemResults.properties);
        });
        return Promise.all(lineItemPromises);
    })
    .then(resultsArray => {
        console.log('here', JSON.stringify(resultsArray));

        // collect properties to update
        let properties = {};
        let has_module = false;
        let has_battery = false;
        let has_inverter = false;
        let has_ev_chargers = false;
        let has_battery_expansion = false;
        //let has_backup_switch = false;

        resultsArray.forEach(function (value) {
            console.log('value', value);

            if(value.product_category == "Module") {
                Object.assign(properties, {
                    'module_brand': value.manufacturer,
                    'modules': value.name,
                    'module_qty': value.quantity,
                    'module_dc_size': value.dc_size,
                    'module_length': value.length,
                    'module_width': value.width
                });
                has_module = true;
            }
            if(value.product_category == "Battery") {
                Object.assign(properties, {
                    'battery_brand': value.manufacturer,
                    'battery': value.name,
                    'battery_qty': value.quantity,
                    'battery_size': value.size__kwh_
                });
                has_battery = true;
            }
            if(value.product_category == "Inverter") {
                Object.assign(properties, {
                    'inverter_brand': value.manufacturer,
                    'inverter': value.name,
                    'inverter_ac_size': value.ac_size
                });
                has_inverter = true;
            }
            if(value.product_category == "EV Charger") {
                Object.assign(properties, {
                    'ev_chargers': value.quantity
                });
                has_ev_chargers = true;
            }
            if(value.product_category == "Battery Expansion") {
                Object.assign(properties, {
                    'battery_expansion': value.name,
                    'battery_expansion_qty': value.quantity
                });
                has_battery_expansion = true;
            }
            /*if(value.product_category == "Backup Switch") {
                Object.assign(properties, {
                    'backup_switch': value.name,
                    'backup_switch_qty': value.quantity
                });
                has_backup_switch = true;
            }*/
        });

        // reset missing categories
        if(!has_module) {
            Object.assign(properties, {
                'module_brand': "", 'modules': "", 'module_qty': "",
                'module_dc_size': "", 'module_length': "", 'module_width': ""
            });
        }
        if(!has_battery) {
            Object.assign(properties, {
                'battery_brand': "", 'battery': "", 'battery_qty': "", 'battery_size': ""
            });
        }
        if(!has_inverter) {
            Object.assign(properties, {
                'inverter_brand': "", 'inverter': "", 'inverter_ac_size': ""
            });
        }
        if(!has_ev_chargers) {
            Object.assign(properties, {'ev_chargers': ""});
        }
        if(!has_battery_expansion) {
            Object.assign(properties, {
                'battery_expansion': "", 'battery_expansion_qty': ""
            });
        }
        /*if(!has_backup_switch) {
            Object.assign(properties, {
                'backup_switch': "", 'backup_switch_qty': ""
            });
        }*/

        // single update call with all properties
        return hubspotClient.crm.deals.basicApi.update(event.object.objectId, { properties });
    })
    .then(updateResponse => {
        console.log(updateResponse);
        callback({}); // only call callback once, after all operations complete
    })
    .catch((err) => {
        console.error(err);
        callback(err); // pass error to callback
    });
};
